with open("atlas/templates/atlas/base.html", encoding="utf-8") as f:
    c = f.read()

replacements = [
    ('👤 <span data-i18n="menu.perfil">', svgs['perfil'] + ' <span data-i18n="menu.perfil">'),
    ('🌿 <span data-i18n="menu.atlas">',  svgs['atlas'] + ' <span data-i18n="menu.atlas">'),
    ('❤️ <span data-i18n="menu.favoritos">', svgs['favoritos'] + ' <span data-i18n="menu.favoritos">'),
    ('📍 <span data-i18n="menu.avistamientos">', svgs['avistamientos'] + ' <span data-i18n="menu.avistamientos">'),
    ('🚪 <span data-i18n="menu.logout">', svgs['cerrar'] + ' <span data-i18n="menu.logout">'),
    ('👤 Mi perfil', svgs['perfil'] + ' Mi perfil'),
    ('🌿 Mi Atlas',  svgs['atlas'] + ' Mi Atlas'),
    ('❤️ Mis favoritos', svgs['favoritos'] + ' Mis favoritos'),
    ('📍 Mis avistamientos', svgs['avistamientos'] + ' Mis avistamientos'),
]

count = 0
for old, new in replacements:
    if old in c:
        c = c.replace(old, new)
        count += 1
        print("OK:", old[:40])
    else:
        print("NO:", old[:40])

with open("atlas/templates/atlas/base.html", "w", encoding="utf-8") as f:
    f.write(c)
print(f"DONE: {count} reemplazos")
